package com.chaobo.scm.supplier.application.asn;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.infrastructure.persistence.asn.AsnTransportPerformanceMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.*;import java.util.*;
@Service public class AsnTransportPerformanceApplicationService {private final AsnTransportPerformanceMapper mapper;public AsnTransportPerformanceApplicationService(AsnTransportPerformanceMapper mapper){this.mapper=mapper;}@Transactional(readOnly=true)public List<View> arrived(long supplierId,YearMonth period,Long scope){if(scope!=null&&scope!=supplierId)throw new BusinessException(ErrorCode.NOT_FOUND,"运输绩效不存在");var from=period.atDay(1).atStartOfDay().atOffset(ZoneOffset.ofHours(8));var to=period.plusMonths(1).atDay(1).atStartOfDay().atOffset(ZoneOffset.ofHours(8));return mapper.arrived(supplierId,from,to).stream().map(r->new View(r.asnId(),r.shippedAt(),r.arrivedAt(),r.transitMinutes())).toList();}public record View(long asnId,OffsetDateTime shippedAt,OffsetDateTime arrivedAt,long transitMinutes){}}
